async (params, browser) => {
  // Open profile
  await browser.open(`${params.profile_url}`)

  // Wait for profile
  await browser.waitForSelector('.text-heading-xlarge', 15000)

  await browser.wait(1500)

  // Click Message button
  const open_message = await browser.evaluate(`const msgBtn = document.querySelector('button[aria-label*="Message"], a[href*="/messaging/"]'); if (msgBtn) { msgBtn.click(); return { clicked: true }; } return { clicked: false, message: 'Message button not found - you may not be connected' }`)

  await browser.wait(2000)

  // Wait for message input
  await browser.waitForSelector('.msg-form__contenteditable, div[role=\'textbox\'][contenteditable=\'true\']', 10000)

  // Type message
  const type_message = await browser.evaluate(`const el = document.querySelector('.msg-form__contenteditable[contenteditable="true"], .msg-form__contenteditable p, div[role="textbox"][contenteditable="true"]'); if (!el) throw new Error('Message input not found'); el.focus(); document.execCommand('insertText', false, params.message); el.dispatchEvent(new Event('input', {bubbles: true})); return { typed: true }`)

  await browser.wait(500)

  // Send message
  const result = await browser.evaluate(`const sendBtn = document.querySelector('.msg-form__send-button, button[type="submit"].msg-form__send-button, button.msg-form__send-btn'); if (sendBtn) { sendBtn.click(); return { success: true, message: 'Message sent' }; } return { success: false, message: 'Send button not found' }`)

  return result
}
